public static int countEven(int [] values)
{
    int count;
    count = 0;
    for (int i = 0;i < values.length;i++)
    {
        if (values[i] % 2 != 1)
        {
            count = count + 1;
        }
        else
        {
            count = count;
        }
    }
    return count;
}

public static int sumValues(int[] values, boolean positivesOnly)
{
    int sum = 0;
    for (int i = 0; i < values.length; i++)
    {
        if (positivesOnly == true)
        {
            if (values[i] >= 0)
            {
                sum += values[i];
            }
        } else
        {
            sum += values[i];
        }
    }
    return sum;
}

public static int oddSum(int[] array)
{
    int total = 0;
    boolean stop = false;
    for (int i = 1; i < array.length; i = i + 2)
    {
        if (stop == false)
        {
            if (array[i] != -1)
            {
                total += array[i];
            }
            else if (array[i] == -1)
            {
                stop = true;
            }
        }
        else
        {
            total = total;
        }
    }
    return total;
}

public static int calculateScore(int changes, int day)
{
    int score = 10;
    for (int i = 0; i < changes; i++)
    {
        score = score - 1;
    }
    if (day == 6 || day == 7)
    {
        return score;
    }
    else
    {
        score = score - 3;
        return score;
    }
}

