public static boolean sumIsEven(int[] values, boolean positivesOnly)
{
    int sum = 0;
    for (int i = 0; i < values.length; i++)
    {
        sum += values[i];
        if (positivesOnly && values[i] < 0)
        {
            sum -= values[i];
        }
    }
    if (sum % 2 != 1)
    {
        return true;
    }
    else
    {
        return false;
    }
}
